# Step 4: Main -----------------------------------------------------------------
################################################################################

def main():
    # ---- User settings --------------------------------------------------------
    cancer_type = "LUAD"
    data_dir = "data"
    output_dir = data_dir

    exp_file = os.path.join(
        data_dir,
        f"TCGA_{cancer_type}",
        f"{cancer_type}_rnaseq_log2tpm.tsv",
    )
    snv_file = os.path.join(
        data_dir,
        f"TCGA_{cancer_type}",
        f"{cancer_type}_snv.tsv",
    )
    os.makedirs(output_dir, exist_ok=True)

    # 1) Initialize analysis
    analysis = AnalyzeExpression(
        expression_file=exp_file,
        snv_file=snv_file,
    )

    # 2) Compare tumor and normal expression
    expression_gene = "PLA2G4A"
    paired = True
    comparison = "paired" if paired else "unpaired"

    tumor_normal_data, tumor_normal_stats = (
        analysis.compare_tumor_normal(gene=expression_gene, paired=paired)
    )
    tumor_normal_stats_file = os.path.join(
        output_dir,
        f"{cancer_type}_{expression_gene}_{comparison}_tumor_normal_stats.tsv",
    )
    tumor_normal_stats.to_csv(
        tumor_normal_stats_file,
        sep="\t",
        index=False,
    )

    tumor_normal_plot_file = os.path.join(
        output_dir,
        f"{cancer_type}_{expression_gene}_{comparison}_tumor_normal_box.svg",
    )
    analysis.plot_tumor_normal(
        comparison_data=tumor_normal_data,
        stats_data=tumor_normal_stats,
        gene=expression_gene,
        output_path=tumor_normal_plot_file,
        paired=paired,
    )

    # 3) Compare expression by driver mutation status
    expression_gene = "PLA2G4A"
    driver_gene = "STK11"

    group_data, group_stats = analysis.compare_mutation_groups(
        gene=expression_gene,
        driver_gene=driver_gene,
    )
    group_stats_file = os.path.join(
        output_dir,
        f"{cancer_type}_{expression_gene}_{driver_gene}_mutation_group_stats.tsv",
    )
    group_stats.to_csv(
        group_stats_file,
        sep="\t",
        index=False,
    )

    group_plot_file = os.path.join(
        output_dir,
        f"{cancer_type}_{expression_gene}_{driver_gene}_mutation_group_box.svg",
    )
    analysis.plot_mutation_groups(
        group_data=group_data,
        stats_data=group_stats,
        gene=expression_gene,
        driver_gene=driver_gene,
        output_path=group_plot_file,
    )

    # 4) Plot gene-gene expression scatter plots
    scatter_x_gene = "PLA2G4A"
    scatter_y_gene = "PTGS2"
    plot_normal = True

    sample_type_scatter_file = os.path.join(
        output_dir,
        f"{cancer_type}_{scatter_x_gene}_{scatter_y_gene}_scatter_sample_type.svg",
    )
    analysis.plot_scatter(
        x_gene=scatter_x_gene,
        y_gene=scatter_y_gene,
        output_path=sample_type_scatter_file,
        plot_normal=plot_normal,
    )

    scatter_x_gene = "PLA2G4A"
    scatter_y_gene = "PTGS2"
    driver_gene = "STK11"
    plot_normal = True

    driver_scatter_file = os.path.join(
        output_dir,
        f"{cancer_type}_{scatter_x_gene}_{scatter_y_gene}_{driver_gene}_scatter.svg",
    )
    analysis.plot_scatter(
        x_gene=scatter_x_gene,
        y_gene=scatter_y_gene,
        output_path=driver_scatter_file,
        plot_normal=plot_normal,
        driver_gene=driver_gene,
    )

    # 5) Plot multi-gene heatmap by driver mutation status
    driver_gene = "STK11"
    heatmap_genes = [
        "AKR1C2",
        "CYP2C18",
        "CYP2C19",
        "CYP2W1",
        "CYP4F3",
        "PLA2G4A",
        "PTGES",
        "PTGES2",
        "PTGES3",
        "PTGS2",
    ]
    gene_heatmap_file = os.path.join(
        output_dir,
        f"{cancer_type}_{driver_gene}_gene_group_heatmap.svg",
    )
    analysis.plot_gene_heatmap(
        genes=heatmap_genes,
        output_path=gene_heatmap_file,
        driver_gene=driver_gene,
        plot_normal=True,
        color_percentile=95,
    )


if __name__ == "__main__":
    main()
